const input = $input.first().json;
const text = input.text || input.caption || (input.forwarded_content && input.forwarded_content.text) || '';

const m = text.match(/https?:\/\/[^\s]+/);
let url = null, domain = '';
if (m) {
  url = m[0].replace(/[.,;!?\)\]]+$/, '');
  const dm = url.match(/^https?:\/\/([^\/]+)/); domain = dm ? dm[1].replace(/^www\./,'') : '';
}

let capture_type = 'text';
if (input.has_photo || input.photo) capture_type = 'photo';
else if (input.is_forwarded && url) capture_type = 'forwarded_link';
else if (url) capture_type = 'link';
else if (input.is_forwarded) capture_type = 'forward';

const user_note = url ? text.replace(url, '').trim() : text;

let fetch_url = url;
let fetch_mode = 'html';
if (domain === 'tiktok.com' || domain === 'vm.tiktok.com' || domain.endsWith('.tiktok.com')) {
  fetch_url = 'https://www.tiktok.com/oembed?url=' + encodeURIComponent(url);
  fetch_mode = 'oembed_tiktok';
} else if (domain === 'youtube.com' || domain === 'youtu.be' || domain === 'm.youtube.com') {
  fetch_url = 'https://www.youtube.com/oembed?url=' + encodeURIComponent(url) + '&format=json';
  fetch_mode = 'oembed_youtube';
}

return [{ json: {
  chat_id: input.chat_id, user_id: input.user_id, message_id: input.message_id,
  username: input.username, capture_type, url, domain, user_note, text,
  has_url: Boolean(url), fetch_url, fetch_mode
}}];

const meta = $('Prepare Capture').first().json;
const resp = $input.first().json;
const mode = meta.fetch_mode;

function short(s,n){ if(!s) return ''; s=String(s); return s.length>n ? s.slice(0,n)+'…' : s; }
function esc(s){ return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function decodeHtml(s){ return String(s||'').replace(/&amp;/g,'&').replace(/&quot;/g,'"').replace(/&#39;/g,"'").replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&nbsp;/g,' '); }

let title='', description='', author='', thumbnail='';

if (mode === 'oembed_tiktok' || mode === 'oembed_youtube') {
  const r = resp || {};
  title = r.title || '';
  author = r.author_name || '';
  thumbnail = r.thumbnail_url || '';
  description = title;
} else {
  let html = resp;
  if (typeof html === 'object') html = (resp.data || resp.body || JSON.stringify(resp));
  html = String(html || '').slice(0, 200000);
  const mTitle = html.match(/<title[^>]*>([\s\S]{0,500}?)<\/title>/i);
  const mOgTitle = html.match(/<meta[^>]+property=["']og:title["'][^>]+content=["']([^"']{0,500})["']/i);
  const mDesc = html.match(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']{0,800})["']/i);
  const mOgDesc = html.match(/<meta[^>]+property=["']og:description["'][^>]+content=["']([^"']{0,800})["']/i);
  const mOgImg = html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i);
  const mOgSite = html.match(/<meta[^>]+property=["']og:site_name["'][^>]+content=["']([^"']+)["']/i);
  title = decodeHtml((mOgTitle && mOgTitle[1]) || (mTitle && mTitle[1]) || '').trim();
  description = decodeHtml((mOgDesc && mOgDesc[1]) || (mDesc && mDesc[1]) || '').trim();
  thumbnail = (mOgImg && mOgImg[1]) || '';
  author = decodeHtml((mOgSite && mOgSite[1]) || meta.domain || '');
}

if (!title) title = meta.url || '(без заголовка)';

const needs_firecrawl = !description && (mode === 'html');
const tags = [meta.domain, meta.capture_type].filter(Boolean);
const preview = description || short(title, 400);

const replyLines = [
  `📥 <b>${esc(short(title, 180))}</b>`,
  author ? `<i>${esc(short(author, 100))}</i>` : null,
  `<code>${esc(meta.url)}</code>`,
  preview && preview !== title ? `\n${esc(short(preview, 400))}` : null,
  `\n<i>→ inbox (${esc(meta.capture_type)})</i>`
].filter(Boolean);

return [{ json: {
  chat_id: meta.chat_id, user_id: meta.user_id, message_id: meta.message_id,
  capture_type: meta.capture_type, url: meta.url, domain: meta.domain,
  title: short(title, 500), description: short(description, 1500), preview: short(preview, 1500),
  author: short(author, 200), thumbnail_url: thumbnail,
  user_note: short(meta.user_note, 1000),
  needs_firecrawl, tags_json: '{' + tags.map(function(t){ return '"' + String(t).replace(/"/g,'\\"') + '"'; }).join(',') + '}',
  reply_text: replyLines.join('\n')
}}];
